public int palindromeSubsequence(String s) {
    int n = s.length();
    final int mod = 1000000007;
    int[][] dp = new int[10][n];
    for (int i = 0; i < n; ++i) dp[s.charAt(i) - '0'][i] = 1;
    for (int len = 1; len <= 4; ++len) {
        for (int d = 0; d < 10; ++d) {
            for (int i = 0, j = len; j < n; ++i, ++j) {
                dp[d][j] = (dp[d][j - 1] + (s.charAt(j) - '0' == d ? 1 : 0)) % mod;
            }
        }
    }
    long ans = 0;
    for (int d1 = 0; d1 < 10; ++d1) {
        for (int d2 = 0; d2 < 10; ++d2) {
            ans += ((long) dp[d1][n - 5] * dp[d2][n - 1]) % mod;
        }
    }
    return (int) (ans % mod);
}
